#include <stdio.h>

int main() {
    int hostedYears[] = {2010, 2015, 2016, 2017, 2019};
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        int found = 0;
        for (int i = 0; i < 5; ++i) {
            if (N == hostedYears[i]) { found = 1; break; }
        }
        if (found) printf("HOSTED\n");
        else printf("NOT HOSTED\n");
    }
    return 0;
}

