code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        Set<Integer> hosted = new HashSet<>(Arrays.asList(2010, 2015, 2016, 2017, 2019));
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            int N = Integer.parseInt(br.readLine().trim());
            if (hosted.contains(N)) sb.append("HOSTED");
            else sb.append("NOT HOSTED");
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    hosted = {2010, 2015, 2016, 2017, 2019}
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        out_lines.append("HOSTED" if N in hosted else "NOT HOSTED")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

